:solid #ededed 0.75pt;border-bottom:solid #ededed 0.75pt;border-top:solid #ededed 0.75pt;vertical-align:middle;background-color:#ffffff;padding:1.5pt 6pt 1.5pt 6pt;overflow:hidden;overflow-wrap:break-word;"><p dir="ltr" style="line-height:1.2;margin-top:0pt;margin-bottom:0pt;"><span style="font-size:11.5pt;font-family:Verdana;color:#222222;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;">L</span></p></td><td style="border-left:solid #ededed 0.75pt;border-right:solid #ededed 0.75pt;border-bottom:solid #ededed 0.75pt;border-top:solid #ededed 0.75pt;vertical-align:middle;background-color:#ffffff;padding:1.5pt 6pt 1.5pt 6pt;overflow:hidden;overflow-wrap:break-word;"><p dir="ltr" style="line-height:1.2;margin-top:0pt;margin-bottom:0pt;"><span style="font-size:11.5pt;font-family:Verdana;color:#222222;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;">Ell</span></p></td><td style="border-left:solid #ededed 0.75pt;border-right:solid #ededed 0.75pt;border-bottom:solid #ededed 0.75pt;border-top:solid #ededed 0.75pt;vertical-align:middle;background-color:#ffffff;padding:1.5pt 6pt 1.5pt 6pt;overflow:hidden;overflow-wrap:break-word;"><p dir="ltr" style="line-height:1.2;margin-top:0pt;margin-bottom:0pt;"><span style="font-size:11.5pt;font-family:Verdana;color:#222222;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;">Y</span></p></td><td style="border-left:solid #ededed 0.75pt;border-right:solid #ededed 0.75pt;border-bottom:solid #ededed 0.75pt;border-top:solid #ededed 0.75pt;vertical-align:middle;background-color:#ffffff;padding:1.5pt 6pt 1.5pt 6pt;overflow:hidden;overflow-wrap:break-word;"><p dir="ltr" style="line-height:1.2;margin-top:0pt;margin-bottom:0pt;"><span style="font-size:11.5pt;font-family:Verdana;color:#222222;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;">Ypsilon</span></p></td></tr><tr style="height:0pt"><td style="border-left:solid #ededed 0.75pt;border-right:solid #ededed 0.75pt;border-bottom:solid #ededed 0.75pt;border-top:solid #ededed 0.75pt;vertical-align:middle;background-color:#ffffff;padding:1.5pt 6pt 1.5pt 6pt;overflow:hidden;overflow-wrap:break-word;"><p dir="ltr" style="line-height:1.2;margin-top:0pt;margin-bottom:0pt;"><span style="font-size:11.5pt;font-family:Verdana;color:#222222;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;">M</span></p></td><td style="border-left:solid #ededed 0.75pt;border-right:solid #ededed 0.75pt;border-bottom:solid #ededed 0.75pt;border-top:solid #ededed 0.75pt;vertical-align:middle;background-color:#ffffff;padding:1.5pt 6pt 1.5pt 6pt;overflow:hidden;overflow-wrap:break-word;"><p dir="ltr" style="line-height:1.2;margin-top:0pt;margin-bottom:0pt;"><span style="font-size:11.5pt;font-family:Verdana;color:#222222;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;">Emm</span></p></td><td style="border-left:solid #ededed 0.75pt;border-right:solid #ededed 0.75pt;border-bottom:solid #ededed 0.75pt;border-top:solid #ededed 0.75pt;vertical-align:middle;background-color:#ffffff;padding:1.5pt 6pt 1.5pt 6pt;overflow:hidden;overflow-wrap:break-word;"><p dir="ltr" style="line-height:1.2;margin-top:0pt;margin-bottom:0pt;"><span style="font-size:11.5pt;font-family:Verdana;color:#222222;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;">Z</span></p></td><td style="border-left:solid #ededed 0.75pt;border-right:solid #ededed 0.75pt;border-bottom:solid #ededed 0.75pt;border-top:solid #ededed 0.75pt;vertical-align:middle;background-color:#ffffff;padding:1.5pt 6pt 1.5pt 6pt;overflow:hidden;overflow-wrap:break-word;"><p dir="ltr" style="line-height:1.2;margin-top:0pt;margin-bottom:0pt;"><span style="font-size:11.5pt;font-family:Verdana;color:#222222;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;">Tzett</span></p></td></tr></tbody></table></div><p dir="ltr" style="line-height:1.2;background-color:#ffffff;margin-top:14pt;margin-bottom:0pt;">&nbsp;</p><p dir="ltr" style="line-height:1.2;background-color:#ffffff;margin-top:0pt;margin-bottom:0pt;padding:14pt 0pt 0pt 0pt;"><span style="font-size:16pt;font-family:'Times New Roman';color:#222222;background-color:#ffffff;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;">Un-winding the grammar of German language&nbsp;</span></p><p dir="ltr" style="line-height:1.2;background-color:#ffffff;margin-top:0pt;margin-bottom:0pt;padding:14pt 0pt 0pt 0pt;"><span style="font-size:13.999999999999998pt;font-family:'Times New Roman';color:#222222;background-color:#ffffff;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;">For most people, the grammatical structure of a language is like a nightmare! Grammar is the most arduous task for most learners. Every language has its own sets of rules, regulations, syntax and lexicon. Grammar does set the foundational knowledge for the language, so it is important to set the right foundation by understanding the grammar. For instance, the German language has six tenses: Prasens, Präteritum, Perfekt, Plusquamperfekt, Futur I and Futur II.</span></p><ul style="margin-top:0;margin-bottom:0;padding-inline-start:48px;"><li dir="ltr" style="list-style-type:disc;font-size:13.999999999999998pt;font-family:'Times New Roman';color:#222222;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;margin-left: 15.75pt;" aria-level="1"><p dir="ltr" style="line-height:1.2;background-color:#ffffff;margin-top:14pt;margin-bottom:0pt;padding:0pt 0pt 7.5pt 0pt;" role="presentation"><span style="font-size:13.999999999999998pt;font-family:'Times New Roman';color:#222222;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;">Präsens relates to the Present tense in English,</span></p></li><li dir="ltr" style="list-style-type:disc;font-size:13.999999999999998pt;font-family:'Times New Roman';color:#222222;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;margin-left: 15.75pt;" aria-level="1"><p dir="ltr" style="line-height:1.2;background-color:#ffffff;margin-top:0pt;margin-bottom:0pt;padding:0pt 0pt 7.5pt 0pt;" role="presentation"><span style="font-size:13.999999999999998pt;font-family:'Times New Roman';color:#222222;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;">Präteritum relates to Past tenses,</span></p></li><li dir="ltr" style="list-style-type:disc;font-size:13.999999999999998pt;font-family:'Times New Roman';color:#222222;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;margin-left: 15.75pt;" aria-level="1"><p dir="ltr" style="line-height:1.2;background-color:#ffffff;margin-top:0pt;margin-bottom:0pt;padding:0pt 0pt 7.5pt 0pt;" role="presentation"><span style="font-size:13.999999999999998pt;font-family:'Times New Roman';color:#222222;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;">Plusquamperfekt relates to Past Perfect,</span></p></li><li dir="ltr" style="list-style-type:disc;font-size:13.999999999999998pt;font-family:'Times New Roman';color:#222222;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;margin-left: 15.75pt;" aria-level="1"><p dir="ltr" style="line-height:1.2;background-color:#ffffff;margin-top:0pt;margin-bottom:0pt;padding:0pt 0pt 7.5pt 0pt;" role="presentation"><span style="font-size:13.999999999999998pt;font-family:'Times New Roman';color:#222222;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;">Futur I relates to the Future tense,</span></p></li><li dir="ltr" style="list-style-type:disc;font-size:13.999999999999998pt;font-family:'Times New Roman';color:#222222;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;margin-left: 15.75pt;" aria-level="1"><p dir="ltr" style="line-height:1.2;background-color:#ffffff;margin-top:0pt;margin-bottom:0pt;" role="presentation"><span style="font-size:13.999999999999998pt;font-family:'Times New Roman';color:#222222;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;">Futur II relates to the Future perfect plus “will” and “have”.</span></p></li></ul><p dir="ltr" style="line-height:1.2;background-color:#ffffff;margin-top:14pt;margin-bottom:0pt;"><span style="font-size:13.999999999999998pt;font-family:'Times New Roman';color:#222222;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;">The relations mentioned above are in no way entirely accurate or complete in their relevance. However, it will make it easier for you to begin understand the grammar of German language. The tenses have four cases in this language: Nominative, Accusative, Dative and Genitive. Here’s a tricky thing about this language that many people have mentioned before-&nbsp;</span></p><ul style="margin-top:0;margin-bottom:0;padding-inline-start:48px;"><li dir="ltr" style="list-style-type:disc;font-size:18pt;font-family:'Times New Roman';color:#222222;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;" aria-level="1"><p dir="ltr" style="line-height:1.2;background-color:#ffffff;margin-top:14pt;margin-bottom:0pt;" role="presentation"><span style="font-size:13.999999999999998pt;font-family:'Times New Roman';color:#222222;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;">German has three noun prepositions for each gender: die (for feminine nouns), der (for masculine nouns), and das (for neutral gender). This means that with every new word that you might learn in this language, you will have to understand which preposition comes in front of it. It might be a little confusing in the beginning as the biological gender may not match with the grammatical gender. There are also certain rules determining which noun gets which article with its exceptions.&nbsp;</span></p></li><li dir="ltr" style="list-style-type:disc;font-size:22pt;font-family:'Times New Roman';color:#222222;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;" aria-level="1"><p dir="ltr" style="line-height:1.2;background-color:#ffffff;margin-top:0pt;margin-bottom:0pt;" role="presentation"><span style="font-size:13.999999999999998pt;font-family:'Times New Roman';color:#222222;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;">The 16 forms that “the” of English takes on German in different cases and gender.</span></p></li></ul><p dir="ltr" style="line-height:1.2;background-color:#ffffff;margin-top:14pt;margin-bottom:0pt;"><span style="font-size:13.999999999999998pt;font-family:'Times New Roman';color:#222222;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;">There are many such rules but fret not because gradually, with time you will be able to memorize all of them. You will get into the habit of understand it and at </span><span style="font-size:13.999999999999998pt;font-family:'Times New Roman';color:#222222;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;">Langma School of Languages,</span><span style="font-size:13.999999999999998pt;font-family:'Times New Roman';color:#222222;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;"> we help you with the best faculty, study material and proper guidance to help you understand these convoluted topics. Gradually, you will progress and these grammar fundamentals will soon start making sense to you.&nbsp;</span></p><p dir="ltr" style="line-height:1.2;background-color:#ffffff;margin-top:0pt;margin-bottom:0pt;padding:14pt 0pt 0pt 0pt;"><span style="font-size:16pt;font-family:'Times New Roman';color:#222222;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;">German Phrases and Expressions.&nbsp;</span></p><p dir="ltr" style="line-height:1.2;background-color:#ffffff;margin-top:0pt;margin-bottom:0pt;padding:14pt 0pt 0pt 0pt;"><span style="font-size:13.999999999999998pt;font-family:'Times New Roman';color:#222222;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;">Starting a new language might seem like a daunting prospect and being bogged down with tons of grammar rules and regulations might discourage you. So, make sure not to make language extremely complicated while just starting off.&nbsp;</span></p><p dir="ltr" style="line-height:1.2;background-color:#ffffff;margin-top:0pt;margin-bottom:0pt;padding:14pt 0pt 0pt 0pt;"><span style="font-size:13.999999999999998pt;font-family:'Times New Roman';color:#222222;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;">Remember to enjoy the learning process and make it a joyous experience. Therefore, at Langma School of Languages, we include some interesting and intriguing things in the curriculum that grabs the attention of the students, and keeps them motivated.&nbsp;</span></p><p dir="ltr" style="line-height:1.2;background-color:#ffffff;margin-top:0pt;margin-bottom:0pt;padding:14pt 0pt 0pt 0pt;"><span style="font-size:13.999999999999998pt;font-family:'Times New Roman';color:#222222;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;">It’s really important to reward yourself for the little achievements, so it’s better to start with something easy such as daily expressions like Hello, or daily conversations. It will not only boost your self-confidence but also make you feel that you have learned something. Here are a few basic German expressions and daily greetings that might help you get started.&nbsp;</span></p><p dir="ltr" style="line-height:1.3800000000000001;background-color:#ffffff;margin-top:0pt;margin-bottom:12.75pt;padding:20.25pt 0pt 0pt 0pt;"><span style="font-size:16.5pt;font-family:Arial;color:#111111;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;">How To Say The Following in German</span></p><p dir="ltr" style="line-height:1.2;background-color:#ffffff;margin-top:14pt;margin-bottom:0pt;"><span id="docs-internal-guid-02672737-7fff-aed0-9fc4-5096ec50b29b"></span></p><div dir="ltr" style="margin-left:-10pt;" align="left">
                                    <table style="border:none;border-collapse:collapse;"><colgroup><col width="400"><col width="400"></colgroup><tbody><tr style="height:0pt"><td style="border-left:solid #ededed 0.75pt;border-right:solid #ededed 0.75pt;border-bottom:solid #ededed 0.75pt;border-top:solid #ededed 0.75pt;vertical-align:middle;background-color:#f3f3f3;padding:1.5pt 6pt 1.5pt 6pt;overflow:hidden;overflow-wrap:break-word;"><p dir="ltr" style="line-height:1.2;background-color:#ffffff;margin-top:0pt;margin-bottom:0pt;"><span style="font-size:11.5pt;font-family:'Times New Roman';color:#222222;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;">Hallo!</span><span style="font-size:11.5pt;font-family:'Times New Roman';color:#222222;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;">&nbsp;– Hello!</span></p></td><td style="border-left:solid #ededed 0.75pt;border-right:solid #ededed 0.75pt;border-bottom:solid #ededed 0.75pt;border-top:solid #ededed 0.75pt;vertical-align:middle;background-color:#f3f3f3;padding:1.5pt 6pt 1.5pt 6pt;overflow:hidden;overflow-wrap:break-word;"><p dir="ltr" style="line-height:1.2;background-color:#ffffff;margin-top:0pt;margin-bottom:0pt;"><span style="font-size:11.5pt;font-family:'Times New Roman';color:#222222;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;">Wie geht’s?</span><span style="font-size:11.5pt;font-family:'Times New Roman';color:#222222;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;">&nbsp;– How are you?</span></p></td></tr><tr style="height:0pt"><td style="border-left:solid #ededed 0.75pt;border-right:solid #ededed 0.75pt;border-bottom:solid #ededed 0.75pt;border-top:solid #ededed 0.75pt;vertical-align:middle;background-color:#f3f3f3;padding:1.5pt 6pt 1.5pt 6pt;overflow:hidden;overflow-wrap:break-word;"><p dir="ltr" style="line-height:1.2;background-color:#ffffff;margin-top:0pt;margin-bottom:0pt;"><span style="font-size:11.5pt;font-family:'Times New Roman';color:#222222;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;">Danke!</span><span style="font-size:11.5pt;font-family:'Times New Roman';color:#222222;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;">&nbsp;– Thank you!</span></p></td><td style="border-left:solid #ededed 0.75pt;border-right:solid #ededed 0.75pt;border-bottom:solid #ededed 0.75pt;border-top:solid #ededed 0.75pt;vertical-align:middle;background-color:#f3f3f3;padding:1.5pt 6pt 1.5pt 6pt;overflow:hidden;overflow-wrap:break-word;"><p dir="ltr" style="line-height:1.2;background-color:#ffffff;margin-top:0pt;margin-bottom:0pt;"><span style="font-size:11.5pt;font-family:'Times New Roman';color:#222222;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;">Mir geht’s gut.</span><span style="font-size:11.5pt;font-family:'Times New Roman';color:#222222;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;">&nbsp; – I’m doing well</span></p></td></tr><tr style="height:0pt"><td style="border-left:solid #ededed 0.75pt;border-right:solid #ededed 0.75pt;border-bottom:solid #ededed 0.75pt;border-top:solid #ededed 0.75pt;vertical-align:middle;background-color:#f3f3f3;padding:1.5pt 6pt 1.5pt 6pt;overflow:hidden;overflow-wrap:break-word;"><p dir="ltr" style="line-height:1.2;background-color:#ffffff;margin-top:0pt;margin-bottom:0pt;"><span style="font-size:11.5pt;font-family:'Times New Roman';color:#222222;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;">Vielen Dank!</span><span style="font-size:11.5pt;font-family:'Times New Roman';color:#222222;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;">&nbsp;–&nbsp; Thank you very much!</span></p></td><td style="border-left:solid #ededed 0.75pt;border-right:solid #ededed 0.75pt;border-bottom:solid #ededed 0.75pt;border-top:solid #ededed 0.75pt;vertical-align:middle;background-color:#f3f3f3;padding:1.5pt 6pt 1.5pt 6pt;overflow:hidden;overflow-wrap:break-word;"><p dir="ltr" style="line-height:1.2;background-color:#ffffff;margin-top:0pt;margin-bottom:0pt;"><span style="font-size:11.5pt;font-family:'Times New Roman';color:#222222;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;">Mir geht’s&nbsp;nicht gut.</span><span style="font-size:11.5pt;font-family:'Times New Roman';color:#222222;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;">&nbsp; – I’m not doing well</span></p></td></tr><tr style="height:0pt"><td style="border-left:solid #ededed 0.75pt;border-right:solid #ededed 0.75pt;border-bottom:solid #ededed 0.75pt;border-top:solid #ededed 0.75pt;vertical-align:middle;background-color:#f3f3f3;padding:1.5pt 6pt 1.5pt 6pt;overflow:hidden;overflow-wrap:break-word;"><p dir="ltr" style="line-height:1.2;background-color:#ffffff;margin-top:0pt;margin-